const STORAGE_PREFIX = "ttv-suechteln-vorst-einsatzplan-";
const MATCHES_PREFIX = "ttv-suechteln-vorst-spielplan-";

const emptyRoundData = (matches) =>
  Object.fromEntries(matches.map((m) => [m.id, { availability: {}, notiz: "", ersatzSpieler: [] }]));

// Reihenfolge der Mannschaften für die "obere Mannschaft"-Regel bei Ersatzspielern:
// Ersatz darf aus jeder Mannschaft außer der eigenen und der direkt darüber
// gemeldeten Mannschaft kommen (übliche Höherspielrecht-Regel).
const TEAM_ORDER = ["t1", "t2", "t3", "t4", "t5", "t6"];
const SENIOR_ORDER = ["s1", "s2"];

function upperTeamId(teamId) {
  let idx = TEAM_ORDER.indexOf(teamId);
  if (idx > 0) return TEAM_ORDER[idx - 1];
  idx = SENIOR_ORDER.indexOf(teamId);
  if (idx > 0) return SENIOR_ORDER[idx - 1];
  return null;
}

function eligibleSubstitutes(team) {
  const upper = upperTeamId(team.id);
  const excluded = new Set([team.id, upper].filter(Boolean));
  const names = new Set();
  TEAMS.forEach((t) => {
    if (excluded.has(t.id)) return;
    t.players.forEach((p) => names.add(p));
  });
  return Array.from(names).sort((a, b) => a.localeCompare(b, "de"));
}

function initials(name) {
  return name.split(" ").map((p) => p[0]).join("").slice(0, 2).toUpperCase();
}

function computeMatchStatus(players, avail, requiredPlayers) {
  const no = players.filter((p) => avail[p] === "no");
  const yes = players.filter((p) => avail[p] === "yes");
  const unsicher = players.filter((p) => avail[p] === "request" || avail[p] === "unclear");
  const open = players.filter((p) => !avail[p]);
  const teamSize = players.length;

  let ersatz = null;
  let warning = null;
  if (teamSize - no.length < requiredPlayers) {
    warning = `Nur ${teamSize - no.length} Spieler fest zugesagt – externer Ersatz nötig!`;
  } else if (no.length === teamSize - requiredPlayers && no.length > 0) {
    ersatz = no.join(", ");
  }
  const complete = open.length === 0 && unsicher.length === 0 && !warning;
  // "filled": die Mannschaft ist einsatzbereit, sobald genug Spieler aktiv
  // zugesagt haben (>= requiredPlayers) – unabhängig davon, ob der Rest des
  // Kaders schon reagiert hat.
  const filled = yes.length >= requiredPlayers;
  return { no, yes, unsicher, open, ersatz, warning, complete, filled, requiredPlayers };
}

function pad(n) {
  return String(n).padStart(2, "0");
}

function matchToDate(m) {
  const [day, month, year] = m.date.split(".").map(Number);
  const [hour, minute] = m.time.split(":").map(Number);
  return new Date(year, month - 1, day, hour, minute);
}

function isoToDMY(iso) {
  if (!iso) return "";
  const [y, m, d] = iso.split("-");
  return `${d}.${m}.${y}`;
}
function dmyToIso(dmy) {
  if (!dmy) return "";
  const [d, m, y] = dmy.split(".");
  return `${y}-${m}-${d}`;
}
const WEEKDAYS = ["So", "Mo", "Di", "Mi", "Do", "Fr", "Sa"];
function weekdayFromDMY(dmy) {
  if (!dmy || dmy.split(".").length !== 3) return "";
  const iso = dmyToIso(dmy);
  const d = new Date(iso + "T00:00:00");
  if (isNaN(d)) return "";
  return WEEKDAYS[d.getDay()];
}

function formatICSDate(d) {
  return (
    d.getFullYear() +
    pad(d.getMonth() + 1) +
    pad(d.getDate()) +
    "T" +
    pad(d.getHours()) +
    pad(d.getMinutes()) +
    "00"
  );
}

function icsEventBlock(team, m, uidSuffix) {
  const start = matchToDate(m);
  const end = new Date(start.getTime() + 3 * 60 * 60 * 1000);
  return [
    "BEGIN:VEVENT",
    `UID:${team.id}-${m.id}-${uidSuffix}@ttve-einsatzplan`,
    `DTSTART:${formatICSDate(start)}`,
    `DTEND:${formatICSDate(end)}`,
    `SUMMARY:${team.label} vs. ${m.opponent} (${m.home ? "Heim" : "Auswärts"})`,
    `LOCATION:${(m.address || "").replace(/,/g, "\\,")}`,
    `DESCRIPTION:${m.home ? "Heimspiel" : "Auswärtsspiel"} – ${team.league}`,
    "END:VEVENT",
  ];
}

function downloadICSBlob(filename, events) {
  const lines = [
    "BEGIN:VCALENDAR",
    "VERSION:2.0",
    "PRODID:-//TTV Einigkeit Süchteln-Vorst//Einsatzplan//DE",
    "CALSCALE:GREGORIAN",
    ...events,
    "END:VCALENDAR",
  ];
  const blob = new Blob([lines.join("\r\n")], { type: "text/calendar;charset=utf-8" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

function downloadICS(team, round) {
  const matches = team.matches[round] || [];
  const events = matches.flatMap((m) => icsEventBlock(team, m, round));
  downloadICSBlob(`${team.label.replace(/\s+/g, "_")}_${round}_Spielplan.ics`, events);
}

function downloadSingleICS(team, m, round) {
  downloadICSBlob(
    `${team.label.replace(/\s+/g, "_")}_vs_${(m.opponent || "Spiel").replace(/\s+/g, "_")}.ics`,
    icsEventBlock(team, m, round)
  );
}

function mapsLink(address) {
  return `https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(address)}`;
}

function whatsappShareUrl(team, m, avail, notiz, ersatzSpieler) {
  const yes = team.players.filter((p) => avail[p] === "yes");
  const no = team.players.filter((p) => avail[p] === "no");
  const request = team.players.filter((p) => avail[p] === "request");
  const unclear = team.players.filter((p) => avail[p] === "unclear");
  const open = team.players.filter((p) => !avail[p]);
  const divider = "──────────────";

  const lines = [
    `🏓 *${team.label}* – ${team.league}`,
    `${m.home ? "🏠 Heimspiel" : "🚌 Auswärtsspiel"} gegen *${m.opponent}*`,
    divider,
    `📅 ${m.weekday}, ${m.date}`,
    `🕐 ${m.time} Uhr`,
  ];
  if (m.address) {
    lines.push(`📍 ${m.address}`, mapsLink(m.address));
  }
  lines.push(divider, `*Rückmeldungen (${yes.length}/${team.players.length} spielen)*`, "");
  lines.push(`✅ Zusagen`, yes.length ? yes.map((p) => `   • ${p}`).join("\n") : "   _noch keine_");
  if (no.length) lines.push("", `❌ Absagen`, no.map((p) => `   • ${p}`).join("\n"));
  if (request.length) lines.push("", `❔ Auf Anfrage`, request.map((p) => `   • ${p}`).join("\n"));
  if (unclear.length) lines.push("", `🟡 In Klärung`, unclear.map((p) => `   • ${p}`).join("\n"));
  if (open.length) lines.push("", `⬜ Noch offen`, open.map((p) => `   • ${p}`).join("\n"));
  if (ersatzSpieler && ersatzSpieler.length) lines.push("", `🟣 *Ersatzspieler*`, ersatzSpieler.map((p) => `   • ${p}`).join("\n"));
  if (notiz) lines.push("", divider, `📝 *Notiz*`, notiz);
  lines.push("", divider, `_Rückmeldung direkt in der App: ${window.location.origin}_`);

  return `https://wa.me/?text=${encodeURIComponent(lines.filter((l) => l !== undefined).join("\n"))}`;
}

function blankMatch() {
  return { id: "n" + Date.now(), date: "", weekday: "", time: "", home: true, opponent: "", address: "" };
}

